// Compute yesterday's date range for the analytics window
// and preserve channel context for use after HTTP call
const items = $input.all();
const now = new Date();
const yesterday = new Date(now);
yesterday.setDate(now.getDate() - 1);
yesterday.setHours(0, 0, 0, 0);
const endOfYesterday = new Date(yesterday);
endOfYesterday.setHours(23, 59, 59, 999);

const startTs = Math.floor(yesterday.getTime() / 1000);
const endTs = Math.floor(endOfYesterday.getTime() / 1000);

return items.map(item => ({
  json: {
    channel_id: item.json.channel_id,
    account_id: item.json.account_id,
    access_token: item.json.access_token,
    start_ts: startTs,
    end_ts: endTs,
    metric_date: yesterday.toISOString().split('T')[0]
  }
}));

// Merge API analytics response with upstream channel context
const apiItems = $input.all();
const channelItems = $('Init - Channel State').all();

return apiItems.map((apiItem, idx) => {
  const channel = channelItems[idx]?.json || {};
  const analyticsData = apiItem.json.analytics?.data || [];

  // Analytics endpoint returns array of daily data points
  // Each point: { start: ts, end: ts, sent: N, delivered: N, read: N, failed: N }
  const totals = analyticsData.reduce((acc, point) => {
    acc.sent      += (point.sent      || 0);
    acc.delivered += (point.delivered || 0);
    acc.read      += (point.read      || 0);
    acc.failed    += (point.failed    || 0);
    return acc;
  }, { sent: 0, delivered: 0, read: 0, failed: 0 });

  return {
    json: {
      channel_id:       channel.channel_id,
      platform:         'whatsapp',
      metric_date:      channel.metric_date,
      // Standard post_metrics columns
      reach:            totals.delivered + totals.read,
      impressions:      totals.sent,
      engagements:      totals.read,
      clicks:           0,
      likes:            0,
      comments:         0,
      shares:           0,
      saves:            0,
      video_views:      0,
      watch_time_seconds: 0,
      profile_visits:   0,
      follower_count:   0,
      // WhatsApp-specific columns
      sent_count:       totals.sent,
      delivered_count:  totals.delivered,
      read_count:       totals.read,
      failed_count:     totals.failed,
      created_at:       new Date().toISOString()
    }
  };
});
